input.command:
python3 -c "
import json

with open('/tmp/all_orders.json') as f:
    orders = json.load(f)

print(f'Total orders: {len(orders)}')

from collections import defaultdict
user_orders = defaultdict(list)
for o in orders:
    user_orders[o['user_id']].append(o)

multi_users = {k: v for k, v in user_orders.items() if len(v) > 1}
print(f'Users with multiple orders: {len(multi_users)}')

dupes = []
for uid, uorders in user_orders.items():
    seen = {}
    for o in uorders:
        key = tuple(sorted(o['product_ids']))
        if key in seen:
            dupes.append((uid, seen[key], o))
        else:
            seen[key] = o

print(f'Exact duplicate product sets (same user): {len(dupes)}')
for uid, o1, o2 in dupes:
    print(f'  User {uid}: {o1[\"id\"]} ({o1[\"status\"]}, {o1[\"total_cents\"]}c) vs {o2[\"id\"]} ({o2[\"status\"]}, {o2[\"total_cents\"]}c)')
    print(f'    Products: {o1[\"product_ids\"]}')
    print(f'    Created: {o1[\"created_at\"]} vs {o2[\"created_at\"]}')
"

